				$(this).attr('timeout', setTimeout(function () { App.Attachments.toggleSelectionEntity('de35464b-29e4-4fcc-8561-ff5a518c95cf', '#' + parent);}, 500));""
	onmouseup=""var parent = $(this).parents('.attachment-list-wrapper')[0].id;
				if (new Date().getTime() &lt; (parseInt($(this).attr('start')) + 500)) {
					clearTimeout($(this).attr('timeout'));
					if ($('#' + parent).prop('deleteMode')) {
						App.Attachments.toggleSelectionEntity('de35464b-29e4-4fcc-8561-ff5a518c95cf', '#' + parent);
					} else {
						App.Attachments.showInfoDialog('de35464b-29e4-4fcc-8561-ff5a518c95cf');
					}
				}""
	onmouseleave=""$(this).attr('start', 0);""
